      opacity: 0,
      duration: 0.05,
      stagger: 0.075,
    },
    "<"
  );

  // fade out overlay
  overlayTimeline.to(".overlay", {
    opacity: 0,
    duration: 0.5,
    delay: 1.5,
  });

  // reveal images
  imagesTimeline.to(".img", {
    clipPath: "polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%)",
    duration: 1,
    delay: 2.5,
    stagger: 0.05,
    ease: "hop",
    onStart: () => {
      setTimeout(() => {
        startImageRotation();
        gsap.to(".loader", { opacity: 0, duration: 0.3 });
