    if (overlay) overlay.style.display = "none";
    if (imageGrid) imageGrid.style.display = "none";

    if (lenis) {
      lenis.start();
    }

    return;
  }

  // disable scrolling during preloader
  if (lenis) {
    lenis.stop();
  }

  init();
});

